 1	// BlastSimulator2026 — i18n module
 2	// Pure TypeScript, no side effects, no DOM.
 3	// Usage: t('blast.fragments', { count: 42 }) → "42 fragments detected"
 4	
 5	import enLocale from './locales/en.json' assert { type: 'json' };
 6	import frLocale from './locales/fr.json' assert { type: 'json' };
 7	
 8	type Locale = 'en' | 'fr';
 9	type Params = Record<string, string | number>;
10	type LocaleData = Record<string, string>;
11	
12	const locales: Record<Locale, LocaleData> = {
13	  en: enLocale as LocaleData,
14	  fr: frLocale as LocaleData,
15	};
16	
17	let currentLocale: Locale = 'en';
18	
19	/** Get the active locale code. */
20	export function getLocale(): Locale {
21	  return currentLocale;
22	}
23	
24	/** Switch the active locale for all subsequent t() calls. */
25	export function setLocale(locale: Locale): void {
26	  currentLocale = locale;
27	}
28	
29	/**
30	 * Translate a key with optional interpolation.
31	 * @param key  - dot-separated translation key (e.g. 'blast.fragments')
32	 * @param params - optional interpolation values ({ count: 42 })
33	 * @returns translated string, or the key itself if not found
34	 *
35	 * Example: t('blast.fragments', { count: 42 }) → "42 fragments detected"
36	 */
37	export function t(key: string, params?: Params): string {
38	  const data = locales[currentLocale];
39	  const template = data[key];
40	
41	  if (template === undefined) {
42	    return key;
43	  }
44	
45	  if (!params) {
46	    return template;
47	  }
48	
49	  return template.replace(/\{(\w+)\}/g, (_match, name: string) => {
50	    const value = params[name];
51	    return value !== undefined ? String(value) : `{${name}}`;
52	  });
53	}

