  1	// BlastSimulator2026 — Survey types and noise-scaled estimation logic
  2	
  3	import { VoxelGrid } from '../world/VoxelGrid.js';
  4	import { Random } from '../math/Random.js';
  5	import {
  6	  SURVEY_BASE_ERROR,
  7	  SURVEY_COVERAGE_RADIUS,
  8	  SURVEY_SKILL_BONUS_PER_LEVEL,
  9	  SURVEY_SEISMIC_GROUP_SIZE,
 10	  SURVEY_ESTIMATE_STEP,
 11	  SURVEY_STALE_TICKS,
 12	  SURVEY_COSTS,
 13	  SURVEY_DURATION_TICKS,
 14	} from '../config/balance.js';
 15	import type { GameState } from '../state/GameState.js';
 16	
 17	/** The three supported methods for surveying a mining site. */
 18	export type SurveyMethod = 'seismic' | 'core_sample' | 'aerial';
 19	
 20	/** Runtime array of every valid SurveyMethod value. */
 21	export const SURVEY_METHODS: SurveyMethod[] = ['seismic', 'core_sample', 'aerial'];
 22	
 23	/**
 24	 * The result produced when a survey is completed.
 25	 *
 26	 * `estimates` is a two-level map:  outer key = resource/zone label,
 27	 * inner key = grade/sub-zone label, value = numeric estimate (e.g. proportion).
 28	 *
 29	 * `confidence` must be in [0, 1].
 30	 */
 31	export interface SurveyResult {
 32	  /** Unique survey record identifier. */
 33	  id: number;
 34	  /** Method used to gather data. */
 35	  method: SurveyMethod;
 36	  /** World-space X coordinate of the survey centre. */
 37	  centerX: number;
 38	  /** World-space Z coordinate of the survey centre. */
 39	  centerZ: number;
 40	  /** Simulation tick on which the survey was completed. */
 41	  completedTick: number;
 42	  /** ID of the surveyor entity that performed the survey. */
 43	  surveyorId: number;
 44	  /** Nested numeric estimates keyed by resource then grade. */
 45	  estimates: Record<string, Record<string, number>>;
 46	  /** Confidence in the estimates, clamped to [0, 1]. */
 47	  confidence: number;
 48	}
 49	
 50	/** Parameters required to compute a noisy survey estimate from a VoxelGrid. */
 51	export interface EstimateSurveyParams {
 52	  id: number;
 53	  method: SurveyMethod;
 54	  centerX: number;
 55	  centerZ: number;
 56	  surveyorId: number;
 57	  /** Surveyor skill level 1–5. Higher values reduce noise. */
 58	  skillLevel: number;
 59	  completedTick: number;
 60	}
 61	
 62	// ── Internal helpers ──────────────────────────────────────────────────────────
 63	
 64	function clamp(val: number, lo: number, hi: number): number {
 65	  return Math.min(hi, Math.max(lo, val));
 66	}
 67	
 68	/** Round a value to the nearest SURVEY_ESTIMATE_STEP (0.05). */
 69	function roundToEstimateStep(val: number): number {
 70	  return Math.round(val / SURVEY_ESTIMATE_STEP) * SURVEY_ESTIMATE_STEP;
 71	}
 72	
 73	/** Scan top→bottom to find the first solid voxel; return y+1, or 0 if all empty. */
 74	function getSurfaceY(grid: VoxelGrid, x: number, z: number): number {
 75	  for (let y = grid.sizeY - 1; y >= 0; y--) {
 76	    const v = grid.getVoxel(x, y, z);
 77	    if (v && v.density > 0) return y + 1;
 78	  }
 79	  return 0;
 80	}
 81	
 82	/**
 83	 * Average a specific ore's density over the subset of `yLevels` that contain
 84	 * solid voxels. Returns `undefined` if no solid voxels are found.
 85	 */
 86	function averageSolidOreDensity(
 87	  grid: VoxelGrid,
 88	  x: number,
 89	  z: number,
 90	  yLevels: number[],
 91	  oreId: string,
 92	): number | undefined {
 93	  const solidVals: number[] = [];
 94	  for (const y of yLevels) {
 95	    const v = grid.getVoxel(x, y, z);
 96	    if (v && v.density > 0) solidVals.push(v.oreDensities[oreId] ?? 0);
 97	  }
 98	  return solidVals.length > 0
 99	    ? solidVals.reduce((sum, val) => sum + val, 0) / solidVals.length
100	    : undefined;

