103	/**
104	 * Seismic density estimate: split `yLevels` into consecutive groups of
105	 * SURVEY_SEISMIC_GROUP_SIZE, average solid voxels within each group, then average
106	 * the group averages. Returns `undefined` if no solid voxels are found.
107	 */
108	function computeSeismicOreDensity(
109	  grid: VoxelGrid,
110	  x: number,
111	  z: number,
112	  yLevels: number[],
113	  oreId: string,
114	): number | undefined {
115	  const groupAvgs: number[] = [];
116	  for (let i = 0; i < yLevels.length; i += SURVEY_SEISMIC_GROUP_SIZE) {
117	    const avg = averageSolidOreDensity(grid, x, z, yLevels.slice(i, i + SURVEY_SEISMIC_GROUP_SIZE), oreId);
118	    if (avg !== undefined) groupAvgs.push(avg);
119	  }
120	  return groupAvgs.length > 0
121	    ? groupAvgs.reduce((sum, val) => sum + val, 0) / groupAvgs.length
122	    : undefined;
123	}
