125	/**
126	 * Produce a noisy, skill-scaled SurveyResult from a VoxelGrid.
127	 *
128	 * - Confidence = clamp(1 − finalError, 0, 1)  where finalError = BASE_ERROR × (1 − skillBonus).
129	 * - Coverage is a disc of COVERAGE_RADIUS[method] around (centerX, centerZ).
130	 * - Seismic: Y values grouped into consecutive triplets; group-average → column-average → add noise.
131	 * - core_sample / aerial: plain average of sampled solid-voxel densities → add noise.
132	 * - Values are clamped to [0,1], rounded to nearest 0.05; zero estimates are omitted.
133	 */
134	export function estimateSurveyResult(
135	  grid: VoxelGrid,
136	  params: EstimateSurveyParams,
137	  rng: Random,
138	): SurveyResult {
139	  const { id, method, centerX, centerZ, surveyorId, skillLevel, completedTick } = params;
140	
141	  const skillBonus = (skillLevel - 1) * SURVEY_SKILL_BONUS_PER_LEVEL;
142	  const finalError = SURVEY_BASE_ERROR[method] * (1 - skillBonus);
143	  const confidence = clamp(1 - finalError, 0, 1);
144	
145	  const radius = SURVEY_COVERAGE_RADIUS[method];
146	  const estimates: Record<string, Record<string, number>> = {};
147	
148	  const xMin = Math.max(0, Math.floor(centerX - radius));
149	  const xMax = Math.min(grid.sizeX - 1, Math.ceil(centerX + radius));
150	  const zMin = Math.max(0, Math.floor(centerZ - radius));
151	  const zMax = Math.min(grid.sizeZ - 1, Math.ceil(centerZ + radius));
152	
153	  for (let x = xMin; x <= xMax; x++) {
154	    for (let z = zMin; z <= zMax; z++) {
155	      if (!grid.isInBounds(x, 0, z)) continue;
156	
157	      const dx = x - centerX;
158	      const dz = z - centerZ;
159	      if (Math.sqrt(dx * dx + dz * dz) > radius) continue;
160	
161	      // Determine which Y levels to sample
162	      let yLevels: number[];
163	      if (method === 'aerial') {
164	        const surfaceY = getSurfaceY(grid, x, z);
165	        yLevels = [surfaceY, surfaceY - 1].filter(y => y >= 0 && y < grid.sizeY);
166	      } else {
167	        yLevels = [];
168	        for (let y = 0; y < grid.sizeY; y++) yLevels.push(y);
169	      }
170	
171	      // Collect ore IDs present in any solid voxel in the sampled range
172	      const allOreIds = new Set<string>();
173	      for (const y of yLevels) {
174	        const v = grid.getVoxel(x, y, z);
175	        if (v && v.density > 0) {
176	          for (const oreId of Object.keys(v.oreDensities)) allOreIds.add(oreId);
177	        }
178	      }
179	      if (allOreIds.size === 0) continue;
180	
181	      const colEstimates: Record<string, number> = {};
182	
183	      for (const oreId of allOreIds) {
184	        const trueDensity = method === 'seismic'
185	          ? computeSeismicOreDensity(grid, x, z, yLevels, oreId)
186	          : averageSolidOreDensity(grid, x, z, yLevels, oreId);
187	        if (trueDensity === undefined) continue;
188	
189	        const noisy = trueDensity + rng.gaussian(0, finalError);
190	        const rounded = roundToEstimateStep(clamp(noisy, 0, 1));
191	        if (rounded > 0) colEstimates[oreId] = rounded;
192	      }
193	
194	      if (Object.keys(colEstimates).length > 0) {
195	        estimates[`${x},${z}`] = colEstimates;
196	      }
197	    }
198	  }
199	
200	  return { id, method, centerX, centerZ, surveyorId, completedTick, estimates, confidence };

